import json

businesses = [{"gmap_id": "gmap_22", "name": "Angel-A Massage"}, {"gmap_id": "gmap_25", "name": "Elite Massage"}, {"gmap_id": "gmap_33", "name": "Happy Spa & Massage (Formerly Hawaii Massage & Spa)"}, {"gmap_id": "gmap_24", "name": "SUSY massage"}, {"gmap_id": "gmap_20", "name": "Aurora Massage"}, {"gmap_id": "gmap_21", "name": "Orient Massage"}, {"gmap_id": "gmap_28", "name": "Good Massage"}]
ratings = [{"gmap_id": "gmap_20", "avg_rating": 4.178571428571429}, {"gmap_id": "gmap_22", "avg_rating": 4.333333333333333}, {"gmap_id": "gmap_25", "avg_rating": 5.0}]

# Convert ratings to a dict
rating_map = {r['gmap_id']: r['avg_rating'] for r in ratings}

result = []
for b in businesses:
    gid = b['gmap_id']
    if gid in rating_map:
        result.append({
            "name": b['name'],
            "average_rating": rating_map[gid]
        })

print("__RESULT__:")
print(json.dumps(result))

